export default function AddWorkerForm() {
    return (
        <div>
            <label>Nombre del proyecto
                <input type="text" placeholder="Nombre" />
            </label>
            <label>Cliente
                <input type="text" placeholder="Rol" />
            </label>
            {["junior", "mid", "senior"].map((option) => (
            <label key={option}>
            <input
                type="radio"
                value={option}
            />
            {option}
            </label>
            ))}
        </div>
    )
}
